    "inlineSchema": "// This is your Prisma schema file,\n// learn more about it in the docs: https://pris.ly/d/prisma-schema\n\n// Looking for ways to speed up your queries, or scale easily with your serverless or edge functions?\n// Try Prisma Accelerate: https://pris.ly/cli/accelerate-init\n\ngenerator client {\n  provider     = \"prisma-client\"\n  output       = \"../generated/prisma\"\n  moduleFormat = \"cjs\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nenum Role {\n  USER\n  ADMIN\n}\n\nmodel User {\n  id        Int                 @id @default(autoincrement())\n  pseudo    String              @unique\n  email     String              @unique\n  password  String\n  ffid      String?\n  avatar    String?\n  role      Role                @default(USER) // ← ajouté\n  rank      Int                 @default(0)\n  points    Int                 @default(0)\n  country   String?\n  wins      Int                 @default(0)\n  createdAt DateTime            @default(now())\n  updatedAt DateTime            @updatedAt\n  rankings  TournamentRanking[]\n\n  registrations Registration[]\n  notifications Notification[]\n  matchResults  MatchResult[]\n}\n\nmodel Tournament {\n  id                    Int                 @id @default(autoincrement())\n  title                 String\n  description           String?\n  game_mode             String\n  max_players           Int\n  current_players       Int                 @default(0)\n  entry_fee             Int                 @default(0)\n  prize_pool            Int\n  status                TournamentStatus    @default(SOON)\n  start_at              DateTime\n  registration_deadline DateTime\n  featured              Boolean             @default(false)\n  createdAt             DateTime            @default(now())\n  updatedAt             DateTime            @updatedAt\n  rankings              TournamentRanking[]\n\n  registrations Registration[]\n  matches       Match[]\n}\n\nmodel Registration {\n  id             Int      @id @default(autoincrement())\n  slot           Int\n  userId         Int\n  tournamentId   Int\n  createdAt      DateTime @default(now())\n  payment_status String   @default(\"PENDING\")\n\n  user       User       @relation(fields: [userId], references: [id])\n  tournament Tournament @relation(fields: [tournamentId], references: [id])\n\n  @@unique([userId, tournamentId])\n}\n\nmodel Notification {\n  id        Int              @id @default(autoincrement())\n  title     String\n  body      String\n  type      NotificationType @default(INFO)\n  read      Boolean          @default(false)\n  userId    Int\n  createdAt DateTime         @default(now())\n\n  user User @relation(fields: [userId], references: [id])\n}\n\nenum TournamentStatus {\n  OPEN\n  SOON\n  FULL\n  ONGOING\n  FINISHED\n}\n\nenum NotificationType {\n  INFO\n  SUCCESS\n  WARNING\n  DANGER\n}\n\n/**\n * ══════════════════════════════════════════\n * AJOUTER À LA FIN DE schema.prisma\n * ══════════════════════════════════════════\n */\n\nenum MatchStatus {\n  PENDING // pas encore commencé\n  LIVE // en cours\n  FINISHED // terminé\n}\n\nmodel Match {\n  id            Int         @id @default(autoincrement())\n  tournamentId  Int\n  round         Int // numéro de manche — 1, 2, 3...\n  map           String // ex: \"Bermuda\", \"Kalahari\", \"Purgatory\"\n  room_id       String? // ID de la room Free Fire\n  room_password String? // mot de passe de la room\n  status        MatchStatus @default(PENDING)\n  scheduled_at  DateTime // heure prévue du match\n  started_at    DateTime? // heure réelle de début\n  finished_at   DateTime? // heure réelle de fin\n  createdAt     DateTime    @default(now())\n  updatedAt     DateTime    @updatedAt\n\n  tournament Tournament    @relation(fields: [tournamentId], references: [id])\n  results    MatchResult[]\n\n  @@unique([tournamentId, round]) // une seule manche X par tournoi\n}\n\nmodel MatchResult {\n  id        Int      @id @default(autoincrement())\n  matchId   Int\n  userId    Int\n  placement Int // classement — 1er, 2ème...\n  kills     Int      @default(0)\n  points    Int      @default(0) // calculé selon placement + kills\n  createdAt DateTime @default(now())\n\n  match Match @relation(fields: [matchId], references: [id])\n  user  User  @relation(fields: [userId], references: [id])\n\n  @@unique([matchId, userId]) // un seul résultat par joueur par match\n  @@unique([matchId, placement]) // un seul joueur par placement par match\n}\n\nmodel TournamentRanking {\n  id           Int      @id @default(autoincrement())\n  tournamentId Int\n  userId       Int\n  totalPoints  Int      @default(0)\n  position     Int\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  tournament Tournament @relation(fields: [tournamentId], references: [id])\n  user       User       @relation(fields: [userId], references: [id])\n\n  @@unique([tournamentId, userId])\n  @@unique([tournamentId, position])\n}\n",
